const livesNextGeneration = (isAlive: boolean, neighborCount: number): boolean =>
  neighborCount === 3 || (isAlive && neighborCount === 2);

type NeighborEntry = { cell: Cell; count: number };

const countNeighbors = (cells: readonly Cell[]): Map<string, NeighborEntry> => {
  const counts = new Map<string, NeighborEntry>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const key = toKey(cell);
      const entry = counts.get(key);
      if (entry) entry.count++;
      else counts.set(key, { cell, count: 1 });
    }
  }
  return counts;
};

export function nextGeneration(cells: readonly Cell[]): readonly Cell[] {
  const aliveKeys = new Set(cells.map(toKey));
  const result: Cell[] = [];
  for (const [key, { cell, count }] of countNeighbors(cells)) {
    if (livesNextGeneration(aliveKeys.has(key), count)) result.push(cell);
  }
  return result;
}
